@app.route('/api/documents', methods=['GET'])
def query_documents():
    try:
        status = request.args.get('status', '').strip()
        author_id = request.args.get('author_id', '').strip()
        tag = request.args.get('tag', '').strip()
        limit = request.args.get('limit', '10')
        skip = request.args.get('skip', '0')
        
        try:
            limit = int(limit)
            skip = int(skip)
        except ValueError:
            return jsonify({'error': 'Invalid limit or skip parameter'}), 400
        
        if limit < 1 or limit > 100:
            limit = 10
        if skip < 0:
            skip = 0
        
        query = {}
        
        if status:
            if not validate_status(status):
                return jsonify({'error': 'Invalid status'}), 400
            query['status'] = status
        
        if author_id:
            if not validate_object_id(author_id):
                return jsonify({'error': 'Invalid author ID'}), 400
            query['author_id'] = ObjectId(author_id)
        
        if tag:
            if not validate_string_field(tag, 1, 50):
                return jsonify({'error': 'Invalid tag'}), 400
            query['tags'] = tag
        
        documents = list(documents_collection.find(query).skip(skip).limit(limit).sort('created_at', -1))
        
        for doc in documents:
            sanitize_document_output(doc)
        
        total = documents_collection.count_documents(query)
        
        return jsonify({
            'documents': documents,
            'total': total,
            'limit': limit,
            'skip': skip
        }), 200
        
    except Exception as e:
        return jsonify({'error': 'Internal server error'}), 500

