# Aggregation Pipelines
@app.route('/api/analytics/documents-by-author', methods=['GET'])
def documents_by_author():
    try:
        pipeline = [
            {
                '$group': {
                    '_id': '$author_id',
                    'total_documents': {'$sum': 1},
                    'total_views': {'$sum': '$views'},
                    'statuses': {'$push': '$status'}
                }
            },
            {
                '$lookup': {
                    'from': 'users',
                    'localField': '_id',
                    'foreignField': '_id',
                    'as': 'author'
                }
            },
            {
                '$unwind': '$author'
            },
            {
                '$project': {
                    '_id': {'$toString': '$_id'},
                    'author_name': '$author.full_name',
                    'author_username': '$author.username',
                    'total_documents': 1,
                    'total_views': 1,
                    'published_count': {
                        '$size': {
                            '$filter': {
                                'input': '$statuses',
                                'as': 'status',
                                'cond': {'$eq': ['$$status', 'published']}
                            }
                        }
                    }
                }
            },
            {
                '$sort': {'total_documents': -1}
            }
        ]
        
        results = list(documents_collection.aggregate(pipeline))
        
        return jsonify({'analytics': results}), 200
        
    except Exception as e:
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/api/analytics/popular-tags', methods=['GET'])
def popular_tags():
    try:
        limit = request.args.get('limit', '10')
        
        try:
            limit = int(limit)
        except ValueError:
            return jsonify({'error': 'Invalid limit parameter'}), 400
        
        if limit < 1 or limit > 50:
            limit = 10
        
        pipeline = [
            {'$unwind': '$tags'},
            {
                '$group': {
                    '_id': '$tags',
                    'count': {'$sum': 1},
                    'total_views': {'$sum': '$views'}
                }
            },
            {'$sort': {'count': -1}},
            {'$limit': limit},
            {
                '$project': {
                    '_id': 0,
                    'tag': '$_id',
                    'count': 1,
                    'total_views': 1
                }
            }
        ]
        
        results = list(documents_collection.aggregate(pipeline))
        
        return jsonify({'tags': results}), 200
        
    except Exception as e:
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/api/analytics/document-stats', methods=['GET'])
def document_stats():
    try:
        pipeline = [
            {
                '$facet': {
                    'by_status': [
                        {
                            '$group': {
                                '_id': '$status',
                                'count': {'$sum': 1}
                            }
                        }
                    ],
                    'overall': [
                        {
                            '$group': {
                                '_id': None,
                                'total_documents': {'$sum': 1},
                                'total_views': {'$sum': '$views'},
                                'avg_views': {'$avg': '$views'}
                            }
                        }
                    ],
                    'recent': [
                        {'$sort': {'created_at': -1}},
                        {'$limit': 5},
                        {
                            '$project': {
                                '_id': {'$toString': '$_id'},
                                'title': 1,
                                'created_at': 1,
                                'views': 1
                            }
                        }
                    ]
                }
            }
        ]
        
        results = list(documents_collection.aggregate(pipeline))
        
        if results:
            stats = results[0]
            if stats['overall']:
                stats['overall'] = stats['overall'][0]
                del stats['overall']['_id']
            
            return jsonify({'statistics': stats}), 200
        
        return jsonify({'statistics': {}}), 200
        
    except Exception as e:
        return jsonify({'error': 'Internal server error'}), 500

